`},d5e=[{id:"root",name:"soroban-studio",type:"folder",children:[{id:"src",name:"src",type:"folder",children:[{id:"main_rs",name:"main.rs",type:"file",children:[]},{id:"lib_rs",name:"lib.rs",type:"file",children:[]}]},{id:"tests",name:"tests",type:"folder",children:[{id:"test_main",name:"main_test.rs",type:"file",children:[]}]},{id:"cargo",name:"Cargo.toml",type:"file",children:[]},{id:"readme",name:"README.md",type:"file",children:[]}]}],wx={"Cargo.toml":`[package]
name = "soroban-hello-world"
